import os
from dotenv import load_dotenv

from tavily import TavilyClient
import google.generativeai as genai
import re

from selenium import webdriver
from selenium.webdriver.chrome.service import Service
from webdriver_manager.chrome import ChromeDriverManager
from bs4 import BeautifulSoup
from selenium.common.exceptions import WebDriverException, TimeoutException

load_dotenv()
os.environ["GOOGLE_API_KEY"] = os.getenv("GOOGLE_API_KEY")
os.environ["TAVILY_API_KEY"] = os.getenv("TAVILY_API_KEY")

client = TavilyClient(api_key=os.environ.get("TAVILY_API_KEY"))

def scrape_restaurantes_info(url):
  if not url:
    print("URL do Tripadvisor não fornecida para scraping.")
    return None
  
  try:
    service = Service(ChromeDriverManager().install())
    options = webdriver.ChromeOptions()
    options.add_argument("--headless")
    options.add_argument("user-agent=Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/91.0.4472.124 Safari/537.36")
    
    driver = webdriver.Chrome(service=service, options=options)
    driver.set_page_load_timeout(30)
  
  except Exception as e:
    print(f"Erro ao configurar o WebDriver: {e}")
    return None

  try:
    print(f"Tentando acessar a URL do Tripadvisor: {url}")
    driver.get(url)
    
    driver.implicitly_wait(10)
    
    response_text = driver.page_source
  
  except TimeoutException:
    print("Tempo de carregamento da página excedido.")
    return None
  except WebDriverException as e:
    print(f"Erro ao carregar a página: {e}. Pode ser um bloqueio do site ou um problema de rede.")
    return None
  finally:
    driver.quit()
  
  soup = BeautifulSoup(response_text, 'html.parser')
  return soup
  
cidade = "Belém"

query = f"""
restaurantes em {cidade} tripadvisor com maior quantidade de reviews e faixa de preço
"""

print("Iniciando uma busca agentica por URLs do Tripadvisor com Tavily...")
tripadvisor_url = None

try :
  tavily_results = client.search(query=query, max_results=5)
  
  if tavily_results and tavily_results["results"]:
    print(f"Tavily encontrou {len(tavily_results['results'])} resultados.")
    
    for result in tavily_results["results"]:
      url = result["url"]
      
      if "tripadvisor.com" in url or "tripadvisor.com.br" in url:
        tripadvisor_url = url
        break
    
    if not tripadvisor_url:
      print("Nenhuma URL do Tripadvisor encontrada nos resultados do Tavily.")
  
  else:
    print("Tavily não retornou resultados ou a resposta foi inesperada.")
except Exception as e:
  print(f"Ocorreu um erro ao usar o Tavily: {e}")
  
